b)';outT{51} = 'y[mm](rms,b)';outT{52} = 'yp[mm](rms,b)';outT{53} = 'x conv fct rms';outT{54} = 'y conv fct rms';outT{55} = 'momentum rsl rms [%]';outT{56} = 'x[mm](fwhm)';outT{57} = 'xp[mm](fwhm)';outT{58} = 'y[mm](fwhm)';outT{59} = 'yp[mm](fwhm)';outT{60} = 'x[mm](fwhm,b)';outT{61} = 'xp[mm](fwhm,b)';outT{62} = 'y[mm](fwhm,b)';outT{63} = 'yp[mm](fwhm,b)';outT{64} = 'x conv fct fwhm';outT{65} = 'y conv fct fwhm';outT{66} = 'momentum rsl [%/mrad]';outT{67} = 'peak momentum error [%]';outT{68} = 'arc Coeff [MeV/mm2]';
